final:
module qam_modulator (
    input [1:0] in,
    output reg [3:0] qam_out
);

always @(*) begin
    case (in)
        2'b00: qam_out = 4'b0000;
        2'b01: qam_out = 4'b0001;
        2'b10: qam_out = 4'b0010;
        2'b11: qam_out = 4'b0011;
        default: qam_out = 4'bxxxx; // Undefined
    endcase
end

endmodule
